import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"浩然正气","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/浩然正气 .md","filePath":"4.资源分区/5.能量池/浩然正气 .md"}'),o={name:"4.资源分区/5.能量池/浩然正气 .md"};function s(d,p,_,l,i,D){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"浩然正气",tabindex:"-1"},[t("浩然正气 "),r("a",{class:"header-anchor",href:"#浩然正气","aria-label":'Permalink to "浩然正气"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003C")])])],-1),n('<h1 id="浩然正气-1" tabindex="-1">浩然正气 <a class="header-anchor" href="#浩然正气-1" aria-label="Permalink to &quot;浩然正气&quot;">​</a></h1><p>浩然正气<br> D+1000</p><p>浩然正气是东方能量池。<br> 浩然正气充塞于天地间，至刚至强，是大义大德造就的人间正气，亦是读书人的气节与骨气。</p><p>修习浩然正气后，人物若是主动与为恶者沆瀣一气、助纣为虐，则浩然正气会黯淡无光，在一影片内失去本资源下所有效果。</p><p>&quot;读圣贤书，所学何事？而今而后，庶几无愧。&quot;</p><p>使用浩然正气时，每轮开始都需要进行一次【风度/决心+学识+专业：儒学+辅助专业：能量感知】的检定，这一轮所动用的浩然正气不可超过检定的成功数。</p><p>周郡王氏承中古仁圣一脉，修身养性，积攒仁德，使自身的浩然正气逐渐壮大而纯粹，终至与天地化为一体，承载天地正道，可凝出浩然圣体法相，内圣外王，诸邪不能侵。<br> 浩然正气是一种通用能量池，关键属性是风度+决心，风度表现你展现浩然正气的能力，决心表现你浩然正气的强度。<br> 作为一种基本用法，当你受到攻击时，你能让浩然正气充斥于体，驱离邪佞，消耗1点浩然正气，在这次防御，意志，强韧或反射豁免上获得+2表现加值，若攻击者是黑暗生物，加值额外提升2点。<br> 浩然正气每天会自然恢复二倍最大值，分摊到每个小时上。<br> 你获得学习后续浩然正气用法的资格，包括圣人九剑，四神剑和三绝技。</p><p>四神剑</p><p>四神剑·为天地立心<br> D+500<br> 先决条件：拥有浩然正气 、持有长剑<br> 以一个整轮动作，消耗2点浩然正气，你引剑向天，承载天地正道，剑之所向，即天地之所向。<br> 人物在全检定与防御上获得3点环境加值，持续一场景。</p><p>差价升级：<br> C+1000/B+2000/A+4000<br> 差价升级后仍然可以使用技艺的较低级别版本。</p><p>则本技艺的能量消耗提升至6/10/14<br> 全检定与防御加值提升至：6/12/风度属性+8点</p><p>四神剑·为生民立命<br> D+500<br> 先决条件：场景内使用过为天地立心<br> 以一个移动动作消耗2点浩然正气，你将剑平指，以天地之道修身致教，引领生民之所为。<br> 你将为天地立心的效果共享给周围10米范围内的友方单位。</p><p>差价升级：C+1000/B+2000/A+4000</p><p>能量消耗提升至：6/10/14<br> 可共享的范围提升至：80米内/敏感范围内/一个国家范围内认同你信念的所有单位。</p><p>四神剑·为往圣继绝学<br> D+500<br> 先决条件：场景内使用过为生民立命<br> 当一个被你精确定位的单位在你的敏感范围内使用了一个需要动作的释放的能力后，你可以自由动作进行一个【风度/决心+学识+专业：儒学+辅助专业：能量感知】的检定，对方以【智力+隐秘+伪装】进行对抗，若你的检定成功数超过了对方与此能力支线等级对应DC（D3C6B12A24S48)之和,则你会知晓这一能力的具体效果，这是一个等同于此能力等级的命运来源的读卡效果。<br> 这之后，你可以花费10XP永久性的记忆下这一能力。你能同时记忆的能力不能超过决心属性上的附加成功+1个。<br> 以一个标准动作，消耗2点浩然正气，你引剑蓄势，身后浮现无数圣贤的虚影，最前的一位与你共握剑柄，正是你打算继承的影像。<br> 你暂时学会一个被此能力所记忆的，且支线不超过D，分数不高于500分的技能（该技能需要至少消耗一个自由动作），持续一个场景，必须拥有推动那种招式或技能所需要的能量，以及满足相关前提，若该技能需要能量推动，你只能以浩然正气来推动。<br> 通过此技能同时能学会的技能只有一个，若你学习第二个，则第一个将失去，且连同所有这个技能带来的好处。</p><p>差价升级：<br> C+1000/B+2000/A+4000</p><p>学会的技能上限变为C+1000/B+2000/A+4000</p><p>四神剑·为万世开太平<br> D+500<br> 先决条件：场景内使用过为往圣继绝学<br> 你挥剑而出，彰显自身圣贤之道，引动天地正气改变世间，诸邪辟易，被攻击者仿佛受这方世界排斥，被天地正气冲刷。<br> 以一个整轮动作，消耗3点浩然正气，对你周围10米范围内所有敌方单位进行攻击检定，不通过防御而是以意志豁免。这次攻击造成正能量伤害。<br> 这次攻击中，你在本场景内每使用过一种支线等级至少为D级的消耗浩然正气的技艺，这次攻击就获得2点神圣加值。</p><p>差价升级：<br> 差价升级后仍然可以使用技艺的较低级别版本。</p><p>C+1000:能量消耗提升至6，现在你能对周围60米范围内的所有敌方单位同时进行攻击，依然使用意志豁免。这次攻击具有法破特性。<br> 在这次攻击中，你在本场景内每使用过一种支线等级至少为C级的、消耗浩然正气的技艺，这次攻击就获得6点神圣加值。</p><p>B+2000：能量消耗提升至10，现在你能对周围160米内的所有敌方单位同时进行攻击，依然使用意志豁免。造成伤害的类型在正能量伤害、精神伤害中取优计算。这次攻击具有法破特性。<br> 在这次攻击中，你在本场景内每使用过一种支线等级至少为B级、消耗浩然正气的技艺，这次攻击就获得决心点神圣加值。</p><p>A+4000:能量消耗提升至14，<br> 现在你能对敏感范围内的所有敌方单位同时进行攻击，依然使用意志豁免。造成的伤害类型在正能量、精神伤害中取优计算。这次攻击直接造成韧性伤害。若命中目标为黑暗生物，其立即死亡，这是A级别影响心灵来源的即死效果。这次攻击具有法破特性。<br> 在这次攻击中，你在本场景内每使用过一种支线等级至少为A级、消耗浩然正气的技艺，这次攻击就获得【决心+风度】属性点神圣加值。</p><p>——————————————————————</p><p>三绝技·富贵不能淫<br> D+500<br> 你免疫D级别影响心灵来源的负面效果。<br> 当你进行意志豁免时，可支付2点浩然正气获得6点神圣加值。<br> 当你承受魅惑或情绪异常点数时，可支付2点浩然正气减少2点异常点数。</p><p>差价升级：<br> C+1000/B+2000/A+4000<br> 差价升级后仍然可以使用技艺的较低级别版本。</p><p>免疫影响心灵的等级提升至C/B/A级。<br> 进行意志豁免时，能量消耗提升至6/10/14，获得的加值提升至12/24/48。<br> 承受魅惑或情绪异常点数时，能量消耗提升至6/10/14，减少的异常点数提升至4/8/16。</p><p>三绝技·贫贱不能移<br> D+500<br> 当你进行反射/强韧豁免时，可以支付2点浩然正气以获得6点神圣加值。<br> 当你被迫移动自身位置时，可以支付2点浩然正气，你被迫移动的距离减少15米。<br> 当你受到伤害时，可以支付2点浩然正气，你受到的伤害值减少1点。</p><p>差价升级：<br> C+1000/B+2000/A+4000<br> 差价升级后仍然可以使用技艺的较低级别版本。</p><p>进行反射/强韧豁免时，能量消耗提升至6/10/14，获得的加值提升至12/24/48点。<br> 当你被迫移动自身位置时，能量消耗提升至6/10/14，被迫移动的距离减少45/180/360米。<br> 当你受到伤害时，能量消耗提升至6/10/14，伤害值降低3/6/10点。</p><p>三绝技·威武不能屈<br> D+500<br> 当你受到攻击后，若对手的攻击检定（计算破除防御前）中DP与附加成功合计后高于你攻击检定中DP与附加成功的合计值，则你可以反射动作支付2点浩然正气，令你自身在一场景内攻击上获得2点加值或1点附加成功，这些都是士气加值。<br> 本能力获得的士气加值与附加成功可以叠加，但若你攻击检定中DP与附加成功的合计值高于你攻击目标攻击检定中DP与附加成功的合计值，则因本能力而高出的这部分DP与附加成功不会生效。</p><p>差价升级：C+1000/B+2000/A+4000<br> 差价升级后仍然可以使用技艺的较低级别版本。</p><p>能量消耗提升至6/10/14<br> 获得的攻击上的加值或附加成功提升至4/8/16点加值或2/4/8点附加成功。</p><p>——————————————————————</p><p>圣人九剑<br> 圣人九剑是中古仁圣的剑法，所有提及的攻击都是近战白刃攻击，你必须使用剑来使用这些技能。</p><p>圣人九剑·刚直不阿<br> D+500<br> 此招牵动天地之间的浩气正气，蜂拥而来。融于剑势，使得这一剑如千仞之壁，强硬不弯，势大难挡。以一个标准动作，消耗3点浩然之气，你进行一次攻击，这次攻击中获得浩然之气关键属性的附加成功之和的环境加值。至少为1。你可以催动你体内的浩然之气与之呼应，每消耗1点浩然之气，额外提升+1环境加值，至多消耗你的关键属性中较低者。<br> 若攻击者是黑暗生物，则本技艺提供的环境加值翻倍。</p><p>圣人九剑·至公无私<br> C+1000<br> 此招劲气力量分布平衡，没有强弱疏密之分，亦无厚薄重轻之别，刚正淳朴，圆转如意，令人破招无门。<br> 以一个标准动作，消耗6点浩然之气，你进行一次攻击，这次攻击具有5点威猛并获得5点技艺加值。在攻击完成后，你在一轮内处于格挡状态。<br> 若攻击目标是黑暗生物，则从本技艺获得的威猛、技艺加值翻倍。</p><p>圣人九剑·内圣外王<br> C+1000<br> 此招将浩气外显，攻守兼备，攻如皇威浩荡，令人难生抵挡之心，守如圣人正仁，令人难起伤人之意。<br> 以一个标准动作，消耗6点浩然正气，进行一次攻击。<br> 这次攻击具有5点破魔、5点神圣加值。<br> 这次攻击无视对方一半的格挡防御，这是C级别影响心灵来源的效果。<br> 若攻击目标是黑暗生物，则本技艺带来的破魔、神圣加值翻倍。</p><p>圣人九剑·仁者无敌<br> C+1500<br> 此招奇诡无比，丝毫不合常理，作为守招，你主动暴露自身的脆弱面，以一身浩然正气令对手短暂动摇或困惑，错失攻击良机。<br> 任何能看见你的对手对你发动近战攻击时，你可以以一个反射动作，消耗6点浩然之气，主动将要害送上，这使对手被迫受到攻击对应的部位攻击减值，你获得相应闪避加值，效果视同攻击咽喉（实际上也可以是心脏或太阳穴，由你选择）。这是一个C级别幻象来源的胁迫效果。<br> 只要对手有心智，你就能进行一次风度属性判定，以判定结果作为对手攻击中额外需要承受的部位攻击减值，并且你获得相应闪避加值。<br> 当这次攻击不对你造成任何伤害，你在下一轮对其进行的攻击将掌握A级先制。</p><p>圣人九剑·不言鬼神<br> A+4000<br> 此招以自身的浩然正气勾连天地，向天挥出无数剑光，借日月映照洒落至正至阳的浩然之气，剑气化作暴雨洒落，甚至足以笼罩一城之地，且有追猎之能，用于扫荡邪佞之徒。<br> 此招式需要在太阳/月亮不被天体遮挡的情况下使用。<br> 以一个标准动作消耗14点浩然正气，对天空进行一次攻击检定，接着你选择视觉范围内的一点，无数剑光会在一轮后跟随日光/月光向目标点倾泻而下。这一场景内，以目标点为中心，周围240米内所有单位每轮都需要进行一个强韧豁免，失败则受到差额的正能量伤害。<br> 此招式的范围会以每轮240米的速度向周围扩散，至多扩散至你敏感范围的二倍。<br> 你可以令这一招式只对黑暗生物生效，若如此做，则黑暗生物所进行的强韧豁免会承受你攻击检定成功数的减值。</p><hr><p>Copyright © 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',41)])])}const h=b(o,[["render",s]]);export{C as __pageData,h as default};
